module top_module(
    input [7:0] a,
    input [7:0] b,
    output reg [8:0] c  // Changed to reg to hold values in always block
);reg [8:0] sum;  // Changed to reg to enable assignment in always block
    wire obf_carry;

    always @(a, b) begin
        sum = a + b;
        // obf_carry does not need to be declared as a register since we can derive it directly
    end

    assign obf_carry = sum[8];  // Assign obf_carry based on sum
    assign c = {obf_carry, sum[7:0]};

endmodule
